void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    vec3 base = GetBlur3(vUv) + GetBlur2(vUv) + GetBlur1(vUv) + texture(sampler_main, vUv)*.8 - .4 ;
a =base.x/8;b = base.y/8; c = base.x/3;
c = c + b + a*b;
a = a + c + a*c;
